import{_ as s,o as t,c as a,ag as n}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"Job Run Analysis","description":"","frontmatter":{},"headers":[],"relativePath":"job-run-analysis.md","filePath":"job-run-analysis.md"}'),o={name:"job-run-analysis.md"};function r(i,e,l,c,u,d){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="job-run-analysis" tabindex="-1">Job Run Analysis <a class="header-anchor" href="#job-run-analysis" aria-label="Permalink to &quot;Job Run Analysis&quot;">​</a></h1><p>Analyze any past Databricks job run directly from the <strong>Jobs</strong> sidebar — no re-execution needed.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>CatalystOps reads the Spark event log from DBFS, extracts the physical execution plans, runs plan analysis, and opens an interactive DAG view. The entire flow runs in VS Code without triggering another job run.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Databricks connection configured (host + token)</li><li><strong>Cluster log delivery to DBFS must be enabled</strong> on the cluster the job used</li></ul><p>To enable log delivery: open your cluster in Databricks → <strong>Advanced Options</strong> → <strong>Logging</strong> → set Destination to <strong>DBFS</strong> and a log path (e.g. <code>dbfs:/cluster-logs</code>). Restart the cluster and re-run the job.</p><div class="warning custom-block"><p class="custom-block-title">Serverless Not Supported</p><p>Serverless jobs do not write Spark event logs to DBFS. Job run analysis requires a classic interactive or job cluster. Use the <a href="/docs/dry-run.html">Dry Run</a> command on the source file for plan analysis of serverless workloads.</p></div><h2 id="using-the-jobs-panel" tabindex="-1">Using the Jobs Panel <a class="header-anchor" href="#using-the-jobs-panel" aria-label="Permalink to &quot;Using the Jobs Panel&quot;">​</a></h2><ol><li>Open the CatalystOps sidebar — find the <strong>Jobs</strong> panel</li><li>The panel lists all jobs in your workspace with their last-run status (Success, Failed, Running, etc.)</li><li><strong>Double-click</strong> any job to analyze its most recent run</li><li>A progress notification tracks fetching run details → reading the event log → building the plan view</li></ol><p>Click <strong>Refresh Jobs</strong> (or run <strong>CatalystOps: Refresh Jobs List</strong>) to reload the list.</p><h2 id="what-you-see" tabindex="-1">What You See <a class="header-anchor" href="#what-you-see" aria-label="Permalink to &quot;What You See&quot;">​</a></h2><p>After analysis completes:</p><ul><li><strong>DAG webview</strong> — interactive plan tree for every query in the run, with issue badges and filter conditions in plain English</li><li><strong>Issues sidebar</strong> — plan issues ranked by severity</li><li><strong>View Source</strong> button — jumps to the notebook or script that generated the plan (if source path is available in the run metadata)</li></ul><h2 id="plan-issues-detected" tabindex="-1">Plan Issues Detected <a class="header-anchor" href="#plan-issues-detected" aria-label="Permalink to &quot;Plan Issues Detected&quot;">​</a></h2><p>The same plan-level detectors as dry run apply: broadcast hints, shuffle exchanges, single-partition bottlenecks, sort aggregation, global windows, missing partition filters, repeated table scans, and more.</p><p>Issues already caught by local static analysis (e.g. <code>CrossJoin</code>, <code>UnionSchemaMismatch</code>) are excluded from the job run DAG to keep the view focused on findings that require an actual execution plan.</p><h2 id="mcp-access" tabindex="-1">MCP Access <a class="header-anchor" href="#mcp-access" aria-label="Permalink to &quot;MCP Access&quot;">​</a></h2><p>The most recent job run analysis is exposed via the MCP tool <code>get_last_job_run_analysis</code>, so Claude or other AI clients can query it without re-running anything.</p>',19)])])}const b=s(o,[["render",r]]);export{p as __pageData,b as default};
